module top_module(
    input clk_inv,
    input reset,
    input d,
    output reg q
);// Power supply signals
    supply1 vdd;
    supply0 gnd;

    always @(posedge clk_inv or negedge reset) begin
        if (reset == 0) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end

endmodule
